<template><div class="page-container"><PageHeader eyebrow="CHARACTERS" title="角色中心" description="查看角色档案、出场作品和关系图谱"/><div class="filter-panel"><el-input v-model="keyword" placeholder="搜索角色名称" @keyup.enter="load"/><el-select v-model="gender" clearable placeholder="性别"><el-option label="男" value="MALE"/><el-option label="女" value="FEMALE"/><el-option label="其他" value="OTHER"/></el-select><el-button type="primary" @click="load">搜索</el-button></div><div v-loading="loading" class="profile-grid"><router-link v-for="item in page.list" :key="item.id" :to="`/characters/${item.id}`" class="profile-card"><div class="profile-image"><img v-if="item.avatarUrl" :src="item.avatarUrl"><div v-else class="avatar-placeholder">{{ item.name?.[0] }}</div></div><div><h3>{{ item.name }}</h3><el-tag size="small">{{ item.gender||'未设置' }}</el-tag><p>{{ truncate(item.description,85) }}</p></div></router-link></div><EmptyState v-if="!loading&&!page.list.length"/><div class="pagination-wrap"><el-pagination background :total="page.total" :page-size="size" v-model:current-page="current" @current-change="load"/></div></div></template>
<script setup>import { onMounted,reactive,ref } from 'vue';import PageHeader from '../../components/PageHeader.vue';import EmptyState from '../../components/EmptyState.vue';import { characterApi } from '../../api/character';import { normalizePage } from '../../utils/page';import { truncate } from '../../utils/format';const keyword=ref(''),gender=ref(''),current=ref(1),size=12,loading=ref(false),page=reactive({list:[],total:0});async function load(){loading.value=true;try{const data=keyword.value?await characterApi.search({keyword:keyword.value,current:current.value,size}):await characterApi.page({current:current.value,size,gender:gender.value||undefined});Object.assign(page,normalizePage(data))}finally{loading.value=false}}onMounted(load)</script>
